var mw = RulesEngine.get_unit_weapons("U_LR_BURNA", GameState.state)
var b = 0; var bs = 0
for mid in mw:
	for w in mw[mid]:
		if str(w).begins_with("burna"): b += 1
		elif str(w).begins_with("big_shoota"): bs += 1
return "%d_burna_%d_bigshoota" % [b, bs]
